using System.Collections.Concurrent;
using sv_878bb11859064bb888246d7723dd8266.Models;

namespace sv_878bb11859064bb888246d7723dd8266.Services;

/// <summary>
/// Singleton in-memory store for wizard data, keyed by a session cookie.
/// Both the static layout (via HttpContext) and interactive pages
/// (via a prerender-persisted session ID) resolve state through this store.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new ApplicationData());

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

namespace sv_878bb11859064bb888246d7723dd8266.Services;

/// <summary>
/// Reads or creates the wizard session cookie so that both the static
/// layout and the interactive pages share the same session ID.
/// </summary>
public static class WizardSessionHelper
{
    public const string CookieName = "WizardSessionId";

    public static string GetOrCreateSessionId(HttpContext httpContext)
    {
        if (httpContext.Request.Cookies.TryGetValue(CookieName, out var id) && !string.IsNullOrEmpty(id))
            return id;

        id = Guid.NewGuid().ToString("N");
        httpContext.Response.Cookies.Append(CookieName, id, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            IsEssential = true,
            MaxAge = TimeSpan.FromHours(4)
        });
        return id;
    }
}

