{"file_text": "@* Static component — rendered in the layout alongside the static MainLayout.
   It reads wizard progress from the server-side store via HttpContext. *@

@using sv_878bb11859064bb888246d7723dd8266.Models
@using sv_878bb11859064bb888246d7723dd8266.Services

@inject WizardStateStore Store
@inject IHttpContextAccessor HttpCtx

@{
    var sessionId = WizardSessionHelper.GetOrCreateSessionId(HttpCtx.HttpContext!);
    var data = Store.GetOrCreate(sessionId);
    var currentPath = HttpCtx.HttpContext!.Request.Path.Value ?? "";
}

<nav class="wizard-progress mb-4">
    <ol class="list-unstyled d-flex justify-content-between mb-1">
        @for (int i = 0; i < steps.Length; i++)
        {
            var step = steps[i];
            var stepNum = i + 1;
            var isActive = currentPath.Equals(step.Href, StringComparison.OrdinalIgnoreCase);
            var isCompleted = data.CompletedSteps.Contains(stepNum);

            <li class="text-center flex-fill">
                <a href="@step.Href"
                   class="text-decoration-none @(isActive ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")">
                    <span class="badge rounded-pill @(isActive ? "bg-primary" : isCompleted ? "bg-success" : "bg-secondary") me-1">
                        @(isCompleted && !isActive ? "✓" : stepNum.ToString())
                    </span>
                    @step.Label
                </a>
            </li>
        }
    </ol>

    @{
        var current = Array.FindIndex(steps, s => currentPath.Equals(s.Href, StringComparison.OrdinalIgnoreCase)) + 1;
    }
    <div class="progress" style="height: 6px;">
        <div class="progress-bar" role="progressbar"
             style="width: @(current * 25)%"
             aria-valuenow="@current" aria-valuemin="0" aria-valuemax="4">
        </div>
    </div>
    <small class="text-muted">Step @current of @steps.Length</small>
</nav>

@code {
    private static readonly (string Href, string Label)[] steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    ];
}
