@page "/apply/experience"
@rendermode InteractiveServer

@using sv_878bb11859064bb888246d7723dd8266.Models
@using sv_878bb11859064bb888246d7723dd8266.Services

@inject WizardStateStore Store
@inject NavigationManager Nav
@inject PersistentComponentState PersistState

<PageTitle>Apply – Experience</PageTitle>
<h3>Step 2: Work Experience</h3>

@for (int i = 0; i < jobs.Count; i++)
{
    var idx = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Job @(idx + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => jobs.RemoveAt(idx)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="jobs[idx].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="jobs[idx].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="jobs[idx].Years" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string sessionId = "";
    private List<JobEntry> jobs = [];

    private PersistingComponentStateSubscription _sub;

    protected override void OnInitialized()
    {
        _sub = PersistState.RegisterOnPersisting(PersistSession);

        if (PersistState.TryTakeFromJson<string>("sessionId", out var restored))
            sessionId = restored!;

        if (!string.IsNullOrEmpty(sessionId))
            LoadFromStore();
    }

    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    protected override void OnParametersSet()
    {
        if (string.IsNullOrEmpty(sessionId) && HttpContext is not null)
        {
            sessionId = WizardSessionHelper.GetOrCreateSessionId(HttpContext);
            LoadFromStore();
        }
    }

    private void LoadFromStore()
    {
        var data = Store.GetOrCreate(sessionId);
        jobs = data.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company,
            Title = j.Title,
            Years = j.Years,
        }).ToList();
    }

    private Task PersistSession()
    {
        PersistState.PersistAsJson("sessionId", sessionId);
        return Task.CompletedTask;
    }

    private void AddJob() => jobs.Add(new JobEntry());

    private void SaveToStore()
    {
        var data = Store.GetOrCreate(sessionId);
        data.JobHistory = jobs.Select(j => new JobEntry
        {
            Company = j.Company,
            Title = j.Title,
            Years = j.Years,
        }).ToList();
    }

    private void Back()
    {
        SaveToStore();
        Nav.NavigateTo("/apply/personal-info");
    }

    private void Next()
    {
        SaveToStore();
        var data = Store.GetOrCreate(sessionId);
        data.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references");
    }

    public void Dispose() => _sub.Dispose();
}

