@page "/apply/review"
@rendermode InteractiveServer

@using sv_878bb11859064bb888246d7723dd8266.Models
@using sv_878bb11859064bb888246d7723dd8266.Services

@inject WizardStateStore Store
@inject NavigationManager Nav
@inject PersistentComponentState PersistState

<PageTitle>Apply – Review</PageTitle>
<h3>Step 4: Review Your Application</h3>

@if (data is not null)
{
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @data.Name</p>
        <p><strong>Email:</strong> @data.Email</p>
    </div>

    <div class="card mb-3 p-3">
        <h5>Work Experience</h5>
        @if (data.JobHistory.Count == 0)
        {
            <p class="text-muted">No jobs entered.</p>
        }
        else
        {
            @foreach (var job in data.JobHistory)
            {
                <div class="mb-2">
                    <strong>@job.Title</strong> at @job.Company — @job.Years years
                </div>
            }
        }
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (data.References.Count == 0)
        {
            <p class="text-muted">No references entered.</p>
        }
        else
        {
            @foreach (var r in data.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email
                </div>
            }
        }
    </div>

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="Back">← Back</button>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-3">Application submitted successfully!</div>
    }
}

@code {
    private string sessionId = "";
    private ApplicationData? data;
    private bool submitted;

    private PersistingComponentStateSubscription _sub;

    protected override void OnInitialized()
    {
        _sub = PersistState.RegisterOnPersisting(PersistSession);

        if (PersistState.TryTakeFromJson<string>("sessionId", out var restored))
            sessionId = restored!;

        if (!string.IsNullOrEmpty(sessionId))
            data = Store.GetOrCreate(sessionId);
    }

    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    protected override void OnParametersSet()
    {
        if (string.IsNullOrEmpty(sessionId) && HttpContext is not null)
        {
            sessionId = WizardSessionHelper.GetOrCreateSessionId(HttpContext);
            data = Store.GetOrCreate(sessionId);
        }
    }

    private Task PersistSession()
    {
        PersistState.PersistAsJson("sessionId", sessionId);
        return Task.CompletedTask;
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        var d = Store.GetOrCreate(sessionId);
        d.CompletedSteps.Add(4);
        submitted = true;
    }

    public void Dispose() => _sub.Dispose();
}

